#include <stdio.h>
#include <stdbool.h>
#define MAX_N 200001
bool dp[MAX_N];
int main() {
    int N, K, Q;
    scanf("%d %d %d", &N, &K, &Q);
    int allowed_numbers[K];
    for (int i = 0; i < K; i++) {
        scanf("%d", &allowed_numbers[i]);
    }
    dp[0] = true;
    for (int i = 0; i < K; i++) {
        for (int j = allowed_numbers[i]; j <= N; j++) {
            if (dp[j - allowed_numbers[i]]) {
                dp[j] = true;
            }
        }
    }
    for (int i = 0; i < Q; i++) {
        int X;
        scanf("%d", &X);
        if (dp[X]) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

